// Validate payload and decode CSV
const body = $input.first().json.body || $input.first().json;
if (!body.client_id) throw new Error('Missing required field: client_id');
if (!body.csv_content) throw new Error('Missing required field: csv_content');

// Decode base64 if needed
let csvText = body.csv_content;
if (!csvText.includes(',') && !csvText.includes('\n')) {
  // Likely base64 encoded
  csvText = Buffer.from(csvText, 'base64').toString('utf-8');
}

return [{
  json: {
    client_id: body.client_id,
    csv_text: csvText,
    pipeline_run_label: body.pipeline_run_label || 'manual-ingest-' + new Date().toISOString().slice(0, 10),
    started_at: new Date().toISOString()
  }
}];

// Parse CSV into keyword records
// Expected SEMrush columns: Keyword, Search Volume, Keyword Difficulty, CPC, Competition, Number of Results, Intent
const ctx = $('Validate_Ingest_Payload').first().json;
const run = $input.first().json;
const pipeline_run_id = (Array.isArray(run) ? run[0] : run)?.id;

const lines = ctx.csv_text.split(/\r?\n/).filter(Boolean);
if (lines.length < 2) throw new Error('CSV has no data rows');

// Detect header row and column indices
const header = lines[0].toLowerCase().split(',').map(h => h.replace(/"/g, '').trim());
const idx = {
  keyword: header.findIndex(h => h === 'keyword'),
  volume: header.findIndex(h => h.includes('search volume') || h === 'volume'),
  kd: header.findIndex(h => h.includes('keyword difficulty') || h === 'kd'),
  cpc: header.findIndex(h => h === 'cpc'),
  competition: header.findIndex(h => h === 'competition'),
  intent: header.findIndex(h => h.includes('intent'))
};
if (idx.keyword === -1) throw new Error('CSV missing Keyword column. Found headers: ' + header.join(', '));

const parseRow = row => {
  // Handle quoted CSV fields
  const fields = [];
  let field = '';
  let inQuotes = false;
  for (const ch of row) {
    if (ch === '"') { inQuotes = !inQuotes; continue; }
    if (ch === ',' && !inQuotes) { fields.push(field.trim()); field = ''; continue; }
    field += ch;
  }
  fields.push(field.trim());
  return fields;
};

const records = lines.slice(1).map(line => {
  const f = parseRow(line);
  const keyword = (f[idx.keyword] || '').toLowerCase().trim();
  if (!keyword) return null;
  return {
    client_id: ctx.client_id,
    pipeline_run_id,
    keyword,
    volume: parseInt(f[idx.volume] || '0', 10) || 0,
    kd: parseFloat(f[idx.kd] || '0') || 0,
    cpc: parseFloat(f[idx.cpc] || '0') || 0,
    competition: parseFloat(f[idx.competition] || '0') || 0,
    intent_semrush: (f[idx.intent] || '').toLowerCase().trim() || null,
    imported_at: new Date().toISOString()
  };
}).filter(Boolean);

return [{
  json: {
    client_id: ctx.client_id,
    pipeline_run_id,
    total_parsed: records.length,
    records
  }
}];

// Also fetch existing raw_keywords for this client to dedupe by keyword text
const ctx = $('Parse_CSV').first().json;
const graveyardRows = $input.first().json || [];
const graveyardIds = new Set((Array.isArray(graveyardRows) ? graveyardRows : []).map(r => r.raw_keyword_id).filter(Boolean));

return [{ json: { ...ctx, graveyard_ids: [...graveyardIds] } }];

// Dedupe: remove keywords already in raw_keywords or in graveyard
const ctx = $('Build_Graveyard_Set').first().json;
const existing = $input.first().json || [];
const existingSet = new Set((Array.isArray(existing) ? existing : []).map(r => r.keyword?.toLowerCase()));

const newRecords = ctx.records.filter(r => !existingSet.has(r.keyword));

const stats = {
  total_parsed: ctx.total_parsed,
  duplicate_skipped: ctx.total_parsed - newRecords.length,
  to_insert: newRecords.length
};

return [{
  json: {
    client_id: ctx.client_id,
    pipeline_run_id: ctx.pipeline_run_id,
    new_records: newRecords,
    stats
  }
}];

// Split new_records into chunks of 500 for Supabase batch inserts
const ctx = $json;
const CHUNK = 500;
const chunks = [];
for (let i = 0; i < ctx.new_records.length; i += CHUNK) {
  chunks.push(ctx.new_records.slice(i, i + CHUNK));
}
if (chunks.length === 0) {
  return [{ json: { ...ctx, chunk: [], chunk_index: 0, total_chunks: 0 } }];
}
return chunks.map((chunk, i) => ({
  json: { client_id: ctx.client_id, pipeline_run_id: ctx.pipeline_run_id, stats: ctx.stats, chunk, chunk_index: i, total_chunks: chunks.length }
}));
